/**
 * Ding-dong chime encoded as base64 data URI.
 *
 * This is the built-in fallback chime played by `playDingDong()` when no
 * custom MP3 has been uploaded by the agency via the "Voix & Annonces" page.
 *
 * Source file: public/sounds/busgo/ding-dong.mp3 (70 KB MP3)
 * Encoded size: ~94 KB base64 (inlined in the JS bundle)
 *
 * Priority chain in playDingDong():
 *   1. Agency-uploaded MP3 (customDingDongUrl) — highest priority
 *   2. This hardcoded base64 chime — realistic default
 *   3. Synthesized oscillator (880Hz/660Hz) — last-resort fallback
 *
 * The base64 is exposed both as raw (for AudioContext.decodeAudioData) and
 * as a data URI (for direct Audio.src assignment).
 */

/**
 * Raw base64 string of the ding-dong MP3 (no data URI prefix).
 * Use this with `fetch()` + `arrayBuffer()` + `AudioContext.decodeAudioData()`.
 */
export const DING_DONG_BASE64_RAW: string =
  '';

/**
 * Ding-dong as a data URI (data:audio/wav;base64,...).
 * Use this directly as `new Audio(src).src` for simple playback.
 *
 * Note: the source file is named .mp3 but is actually a WAV (RIFF/WAVE,
 * 16-bit mono 44100 Hz PCM). The MIME type reflects the actual format.
 */
export const DING_DONG_DATA_URI: string = `data:audio/wav;base64,${DING_DONG_BASE64_RAW}`;

/**
 * Whether the hardcoded ding-dong base64 is available.
 * Always `true` (constant), but exposed for explicit checks.
 */
export const HAS_HARDCODED_DING_DONG: boolean = true;
